<div class="panel"><h1><?= $mode==='create'?__('create'):__('edit') ?> <?= __('invoices') ?></h1><form method="post"><label><?= __('users') ?><select name="user_id"><?php foreach($users as $u): ?><option value="<?= $u['id'] ?>" <?= (int)($item['user_id']??0)===(int)$u['id']?'selected':'' ?>><?= htmlspecialchars($u['email'].' '.trim($u['first_name'].' '.$u['last_name'])) ?></option><?php endforeach; ?></select></label><div class="error"><?= $errors['user_id']??'' ?></div><label><?= __('products') ?><select name="product_id"><?php foreach($products as $p): ?><option value="<?= $p['id'] ?>" <?= (int)($item['product_id']??0)===(int)$p['id']?'selected':'' ?>><?= htmlspecialchars($p['name']) ?> — <?= number_format((float)$p['price'],2) ?></option><?php endforeach; ?></select></label><div class="error"><?= $errors['product_id']??'' ?></div><label><?= __('date') ?><input type="date" name="invoice_date" value="<?= htmlspecialchars($item['invoice_date']??date('Y-m-d')) ?>"></label><label><?= __('quantity') ?><input type="number" name="quantity" min="1" value="<?= htmlspecialchars($item['quantity']??1) ?>"></label><div class="error"><?= $errors['quantity']??'' ?></div><p><button class="btn"><?= __('save') ?></button> <a class="btn btn--secondary" href="index.php?route=invoice/list"><?= __('back') ?></a></p></form></div>
